var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 20시간 경과","JPN":"黒い氾濫の発生から20時間経過","ENG":"20 hours since the Black Flood onset","TWN":"黑色洪災發生20小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……하늘이 여전히 붉네.","JPN":"……空がまだ赤い。","ENG":"...The sky's still red.","TWN":"……天空依舊是紅的。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 세상의 멸망을 눈앞에 두고 있으니까 말이다.","JPN":"ええ。世界の滅亡が目前に迫っているからね。","ENG":"Yes. Because the end of the world is right in front of us.","TWN":"對啊，畢竟世界的毀滅就在眼前啊。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"오르카에게 들은 이야기는 도움이 좀 됐니?","JPN":"オルカの話は役に立った？","ENG":"Did what Orca told you help at all?","TWN":"奧爾卡說得那些話有幫助嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"도움이 되긴 무슨.","JPN":"役に立つもなにも。","ENG":"Help? Not really.","TWN":"哪有什麼幫助。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 꼬맹이한테 그런 소리 들으니까 마음만 복잡해지던데.","JPN":"あのガキの話を聞いたら余計複雑な気持ちになったちまったよ。","ENG":"Hearing that from a kid just made my head even messier.","TWN":"聽完那小鬼說得話，我的心裡反而更亂了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"우리는 프론트 베이로 돌아가는 거야?","JPN":"フロントベイに戻るのか？　あたちたち。","ENG":"Are we heading back to Front Bay?","TWN":"我們會回前灣嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아니. 우리는 프론트 베이로 돌아가지 않을 거란다.","JPN":"いいえ。私たちはフロントベイには戻らないわ。","ENG":"No. We won't be returning to Front Bay.","TWN":"不，我們不回前灣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"응?","JPN":"あ？","ENG":"...Huh?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그럼, 배에 있는 모두를 모아주겠니?","JPN":"そろそろ、船にいるみんなを集めてくれる？","ENG":"Then gather everyone on the ship, will you?","TWN":"那麼，你能集合所有船上的人嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지금부터 우리는 욕조의 마개를 뽑아버릴 계획이거든.","JPN":"今から私たちは、浴槽の栓を抜きに行くのよ。","ENG":"We're about to pull the plug out of the bathtub.","TWN":"從現在開始，我們打算拔掉這個浴缸塞子。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"프론트 베이 관리국은 밀려오는 검은 범람에 대응하느라 여념이 없단다.","JPN":"フロントベイ管理局は、迫りくる黒い氾濫の対応で手一杯。","ENG":"The Front Bay Administration is completely tied up handling the surge of the Black Flood.","TWN":"前灣管理局此刻正忙得不可開交，努力應對湧現的黑色洪災。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래서, 시니어인 잭은 별동대를 창설, 검은 범람의 원인이 되는 크라켄을 우선 토벌하기로 했지.","JPN":"だからシニア・ジャックは別働隊を編成し、黒い氾濫の原因であるクラーケンから討伐することにしたの。","ENG":"So Senior Jack formed a strike team to hunt Kraken, the source of the Black Flood, first.","TWN":"因此Senior傑克創建了分隊，決定優先剿除造成黑色洪災的克拉肯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 이는… 벨라미, 네가 설명해 주겠니?","JPN":"そしてこれは……ベラミー、説明をお願いできる？","ENG":"And as for the details... Bellamy, would you explain?","TWN":"至於這個計畫……貝拉米，你來說明吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"최고 관리자님께서 지시하신 선로전환기의 가동과 관련이 있어요.","JPN":"最高管理者様が指示した線路転換器の稼働と関連しています。","ENG":"It relates to activating the Track Switcher ordered by the Supreme Administrator.","TWN":"它與最高管理者指示的線路轉換器啟動有關。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"전달해 주신 정보에 의하면, 우리는 마왕의 현실 강림을 저지하기 위해 움직일 겁니다.","JPN":"お伝えいただいた情報によると、私たちは魔王の現実降臨の阻止に向けて、動くことになるようです。","ENG":"According to the information we received, we're moving to stop the Demon Lord's descent into reality.","TWN":"根據收到的情報，我們行動的目的是阻止魔王降臨現實。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"크라켄은 지금껏 심해의 대균열을 틀어막는 마개 역할을 하고 있었단다.","JPN":"クラーケンは今まで、深海の大亀裂を塞ぐ栓のような役割をしていたわ。","ENG":"Kraken has been acting as a stopper, plugging the Grand Dimension Crevice deep in the sea.","TWN":"克拉肯一直充當著深海大峽谷的蓋子角色。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"프론트 베이가 검은 범람에 의해 피해를 입으면서도 완전 토벌을 우려하는 이유가 그것 때문이지.","JPN":"フロントベイが黒い氾濫によって被害を受けながらも、完全討伐を躊躇する理由はそのせい。","ENG":"That's why Front Bay hesitated to fully eliminate it, even with the damage from the Black Flood.","TWN":"這就是為什麼前灣因黑色洪災受損，又擔心完全圍剿的緣故。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"다행히 크라켄은 지난번 검은 범람 때의 상처가 아직 회복되지 않았다는 것을 알아냈단다.","JPN":"幸い、クラーケンは前回の黒い氾濫の時の傷がまだ回復しきっていないことを確認したわ。","ENG":"Fortunately, we discovered Kraken still hasn't recovered from the wounds it suffered last time.","TWN":"幸運的是，我們發現克拉肯在上次黑色洪災中受的傷尚未痊癒。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리는 먼저 프론트 베이가 선로전환기를 가동할 시간을 벌 거야.","JPN":"私たちは、フロントベイが線路転換器を稼働するまでの時間を稼ぐ。","ENG":"Our goal is to buy Front Bay time to activate the Track Switcher.","TWN":"我們要先爭取時間，讓前灣有機會啟動線路轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"본래는 마하 섬을 확보한 뒤, 그곳에 선로전환기를 설치하는 것이 가장 인상적이라고는 하나…….","JPN":"本来ならマッハ島を確保し、そこに線路転換器を設置するのが理想的だったんだけど……","ENG":"Originally, securing Macha Island and installing the Track Switcher there would've been ideal...","TWN":"原本確保瑪查島後，在島上安置轉換器會更理想……"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"아무래도 관리국은 직접 함선을 이끌고 와 선로전환기를 가동할 계획인 것 같구나.","JPN":"どうやら管理局は、直接艦船を持ってきて、線路転換器を稼働する計画のようね。","ENG":"But it seems the Administration plans to bring a ship themselves and activate it directly.","TWN":"但看來管理局打算親自帶艦船過來操作轉換器。"},"stage":{"bg":"OMEN_LOTUS_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리네 아줌마도 알고 있겠지만, 도시 상황은 좋지 않아.","JPN":"タリーのお母さんも知ってると思うけど、都市の状況は芳しくない。","ENG":"Tallie's mom probably knows already, but things in the city are bad.","TWN":"塔莉家的阿姨應該也清楚，城市的情況並不樂觀。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"격벽은 이미 뚫린 지 오래고, 시민들은 관리국 본부로 대피한 상황이라고.","JPN":"隔壁はとっくに突破されてるし、市民は管理局本部に避難してる。","ENG":"The bulwark has long since been breached, and citizens have evacuated to the Administration HQ.","TWN":"隔離牆早已被突破，市民們全都撤往管理局本部。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"듣자 하니, 프론트 베이의 공인 카운터는 10년 전부터 요양 중이라 들었는데…….","JPN":"聞いた話だと、フロントベイの公認カウンターは10年前から療養中らしいけど……","ENG":"And from what I've heard, Front Bay's Official Counter has been bedridden for ten years...","TWN":"聽說前灣區公認制裁者從10年前就一直在療養……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이런 상황에서 우리가 그런 도박 수를 강행해야 할 이유가 뭐지?","JPN":"こんな状況で、あたしたちがそんな賭けに出なきゃならない理由って何？","ENG":"So why are we even taking a gamble like this?","TWN":"在這種情況下，我們為什麼要冒這種險呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"좋은 질문이구나, 에이버리의 아이야.","JPN":"いいことを聞いてくれたわ、エイバリーの子。","ENG":"A good question, child of Avery.","TWN":"好問題，艾維利的孩子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그걸… 어떻게……?","JPN":"なんで……それを……？","ENG":"H-how... did you...?","TWN":"那個……怎麼會……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이정도 위치에 있으면, 알고 싶지 않아도 알게 되는 것들이 있는 법이거든.","JPN":"この位置にいると、知りたくなくても知ってしまうことがあるのよ。","ENG":"At my position, there are things you learn whether you want to or not.","TWN":"到了這個位置，即使不想知道，也會知道一些事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"물음에 대한 답을 해주자면… 이런 도박 수를 강행할 수밖에 없는 거란다.","JPN":"質問に答えると……賭けに出るしかないの。","ENG":"To answer your question... We have no choice but to take this gamble.","TWN":"回到問題……我們只能必須強行進行這種賭注。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"CSE 레벨도 무시하지 못할 정도로 높아진 지금.","JPN":"CSEレベルも無視できないほど上昇している今。","ENG":"With the CSE level this high...","TWN":"如今CSE等級已高到無法忽視。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"도시를 지키기 위해선 역으로 모든 것을 크라켄과 대균열에 쏟아부어야 하는 상황에 온 거지.","JPN":"都市を守るためには、逆にクラーケンと大亀裂に全力を注がなければならない状況になってしまったのね。","ENG":"Protecting the city means pouring everything we have into Kraken and the Grand Dimension Crevice.","TWN":"為了保護城市，我們只能反向把一切力量集中在克拉肯和大峽谷。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄을 토벌했다고 쳐.","JPN":"クラーケンを討伐したとして。","ENG":"Let's say we defeat Kraken.","TWN":"假如我們真的剿滅了克拉肯，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그다음은 관리국이 올 때까지 손가락만 빨고 있으면 되는 거야?","JPN":"その次は？　管理局が来るまで指加えて待っていればいいのか？","ENG":"Then what? Just sit around until the Administration arrives?","TWN":"接下來就只要雙手張開等管理局來就可以了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"두 번째 계획은 간단하단다.","JPN":"その次はシンプルよ。","ENG":"The second plan is simple.","TWN":"第二個計劃很簡單。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"바로 이 총을 근처에서 쏘면 되는 거지.","JPN":"この銃を至近距離で撃てばいい。","ENG":"We fire this gun from close range.","TWN":"只要在附近開槍就行了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저 총은……?","JPN":"あの銃は……？","ENG":"That gun...","TWN":"那把槍……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 총을 왜 아줌마가 들고 있는 거야……?","JPN":"その銃をなんでおばさんが持ってるんだ……？","ENG":"Why are you holding that gun...?","TWN":"為什麼阿姨會拿著那把槍……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"어머? 너희들… 설마 이 총을 알고 있는 거니?","JPN":"あら？　あなたたち……この銃のことを知っているの？","ENG":"Oh? You... know about this gun?","TWN":"哦？你們……難道認識這把槍？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"시치미 떼지 마.","JPN":"とぼけんなよ。","ENG":"Don't play dumb with me.","TWN":"別裝傻了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도 같은 총을 어릴 적부터 갖고 있었으니까.","JPN":"あたしもガキの頃から同じ銃を持ってた。","ENG":"I've had the same gun since I was a kid.","TWN":"我從小就帶著同樣的槍。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 총은… 내가 보육원에 맡겨질 때 같이 맡겨진 거라고 들었어.","JPN":"この銃は……あたしが孤児院に預けられたとき、一緒に預けられたものだと聞いた。","ENG":"This gun... I heard it was left with me when I was dropped off at the orphanage.","TWN":"這把槍……據說是我被送到孤兒院時一起交付的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"말이 총이지, 장식품에 불과했지만, 중요한 건 여기 새겨진 음각이야.","JPN":"銃とはいってもただの装飾品に過ぎないんだけど、重要なのはそれじゃない。ここに刻まれた文字だ。","ENG":"It may be just a decorative piece, but what matters is the engraving.","TWN":"雖然只是一把裝飾用的槍，但重點在於上面刻著的字。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>선장 에이버리가, 영원한 친구 보니에게</color>라고 쓰여 있어.","JPN":"<color=#ffd34c>船長エイバリーより、永遠の友ボニーへ</color>と書かれてる。","ENG":"<color=#ffd34c>To my eternal friend Bonny, Captain Avery.</color>","TWN":"<color=#ffd34c>船長艾維利，致永遠的朋友寶妮</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아줌마. 에이버리랑 무슨 관계야?","JPN":"おばさん、エイバリーとどういう関係なんだ？","ENG":"Auntie Mary. What were you to Avery?","TWN":"阿姨，你和艾維利是什麼關係？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 총에 대해… 에이버리… 그리고 보니란 사람에 대해 알고 있는 거지?","JPN":"この銃について……エイバリー……そしてボニーって人について知ってるんだろ？","ENG":"You know something about this gun... about Avery... and this Bonny, don't you?","TWN":"你認識這把槍……艾維利……還有叫寶妮的人吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"알려줘.","JPN":"教えてくれ。","ENG":"Tell me.","TWN":"告訴我。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아줌마가 알고 있는 전부를.","JPN":"おばさんの知ってることすべて。","ENG":"Everything you know.","TWN":"把你知道的一切都說出來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 그래.","JPN":"ふふ、そうね。","ENG":"Fufu. Very well.","TWN":"呵呵，好吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"비록 프론트 베이에 평화가 찾아온 것은 아니지만…….","JPN":"フロントベイに平和が訪れたわけではないけれど……","ENG":"Front Bay may not be peaceful yet...","TWN":"雖然前灣還沒恢復和平……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"이젠 너희에게 이야기해도 좋을 것 같네?","JPN":"そろそろ、あなたたちに話してあげるべきだわ。","ENG":"But I suppose it's time you heard it.","TWN":"但現在好像可以告訴你們了？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 그 총은 본래 네 엄마…….","JPN":"ええ、もともとその銃はあなたの母親……","ENG":"Yes. That gun originally belonged to your mother...","TWN":"這把槍，本來是妳媽媽……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"<color=#ffd34c>앤 보니</color>의 물건이란다.","JPN":"<color=#ffd34c>アン・ボニー</color>のものよ。","ENG":"It belonged to <color=#ffd34c>Anne Bonny</color>.","TWN":"<color=#ffd34c>安·寶妮</color>的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};